   131	        @SuppressWarnings("unchecked")
   132	        QueryBuilderInterface<F> queryBuilder = (QueryBuilderInterface<F>) queryBuilderByHandledFields.computeIfAbsent(
   133	            dataChart.getData().repositoryClass(),
   134	            clazz -> queryBuilders
   135	                .stream()
   136	                .filter(b -> clazz.isAssignableFrom(b.getClass()))
   137	                .findFirst()
   138	                .orElseThrow(() -> new UnsupportedOperationException("No query builder found for " + clazz))
   139	        );
