   146	        ZonedDateTime endDate) throws IOException {
   147	        @SuppressWarnings("unchecked")
   148	        QueryBuilderInterface<F> queryBuilder = (QueryBuilderInterface<F>) queryBuilderByHandledFields.computeIfAbsent(
   149	            dataChart.getData().repositoryClass(),
   150	            clazz -> queryBuilders
   151	                .stream()
   152	                .filter(b -> clazz.isAssignableFrom(b.getClass()))
   153	                .findFirst()
   154	                .orElseThrow(() -> new UnsupportedOperationException("No query builder found for " + clazz))
   155	        );
   156	
   157	        Double filteredValue = queryBuilder.fetchValue(tenantId, dataChart.getData(), startDate, endDate, dataChart.getData().getNumerator() != null);
   158	
   159	        if (dataChart.getChartOptions() != null && dataChart.getChartOptions().getNumberType().equals(KpiOption.NumberType.PERCENTAGE)) {
   160	            Double totalValue = queryBuilder.fetchValue(tenantId, dataChart.getData(), startDate, endDate, false);
   161	            if (totalValue == null || totalValue == 0)
   162	                return List.of(Map.of("value", 0.0));
   163	            double percentageValue = (filteredValue / totalValue) * 100;
   164	            return List.of(Map.of("value", roundDouble(percentageValue, 2)));
   165	        }
   166	
   167	        return List.of(Map.of("value", roundDouble(filteredValue, 2)));
