    10	    public <F extends Enum<F>> Q addFilters(Q query, Map<F, String> fieldsMapping, List<AbstractFilter<F>> filters) {
    11	        if (filters == null) {
    12	            return query;
    13	        }
    14	
    15	        AtomicReference<Q> finalQuery = new AtomicReference<>(query);
    16	        filters.forEach(
    17	            filter -> finalQuery.set(
    18	                switch (filter) {
    19	                    case Contains<F> f -> contains(finalQuery.get(), fieldsMapping.get(f.getField()), f);
    20	                    case EndsWith<F> f -> endsWith(finalQuery.get(), fieldsMapping.get(f.getField()), f);
    21	                    case EqualTo<F> f -> equalTo(finalQuery.get(), fieldsMapping.get(f.getField()), f);
    22	                    case GreaterThan<F> f -> greaterThan(finalQuery.get(), fieldsMapping.get(f.getField()), f);
    23	                    case GreaterThanOrEqualTo<F> f -> greaterThanOrEqualTo(finalQuery.get(), fieldsMapping.get(f.getField()), f);
    24	                    case In<F> f -> in(finalQuery.get(), fieldsMapping.get(f.getField()), f);
    25	                    case IsFalse<F> f -> isFalse(finalQuery.get(), fieldsMapping.get(f.getField()), f);
