   430	    public static void validateQueryFilters(List<QueryFilter> filters, Resource resource) {
   431	        if (filters == null) {
   432	            return;
   433	        }
   434	        List<String> errors = new ArrayList<>();
   435	        filters.forEach(filter ->
   436	        {
   437	            if (!filter.field().supportedOp().contains(filter.operation())) {
   438	                errors.add(
   439	                    "Operation %s is not supported for field %s. Supported operations are %s".formatted(
   440	                        filter.operation(), filter.field().name(),
   441	                        filter.field().supportedOp().stream().map(Op::name).collect(Collectors.joining(", "))
   442	                    )
   443	                );
   444	            }
   445	            if (!resource.supportedField().contains(filter.field())) {
   446	                errors.add(
   447	                    "Field %s is not supported for resource %s. Supported fields are %s".formatted(
   448	                        filter.field().name(), resource.name(),
   449	                        resource.supportedField().stream().map(Field::name).collect(Collectors.joining(", "))
   450	                    )
   451	                );
   452	            }
   453	        });
   454	        if (!errors.isEmpty()) {
