        List<FlowScope> flowScopes = Enums.fromList(value, FlowScope.class);

        String systemNamespace = this.kestraConfig.getSystemFlowNamespace();
        return switch (operation) {
            case EQUALS -> {
                if (flowScopes.size() > 1) {
                    throw new InvalidQueryFiltersException("Only one scope can be use in the same time for EQUALS operation");
                }
                FlowScope scope = flowScopes.getFirst();
                yield FlowScope.USER.equals(scope) ? field("namespace").ne(systemNamespace) : field("namespace").eq(systemNamespace);
            }
            case NOT_EQUALS -> {
                if (flowScopes.size() > 1) {
                    throw new InvalidQueryFiltersException("Only one scope can be use in the same time for NOT_EQUALS operation");
                }
                FlowScope scope = flowScopes.getFirst();
                yield FlowScope.USER.equals(scope) ? field("namespace").eq(systemNamespace) : field("namespace").ne(systemNamespace);
            }
            case IN -> {
                boolean hasUser = flowScopes.contains(FlowScope.USER);
                boolean hasSystem = flowScopes.contains(FlowScope.SYSTEM);
                if (hasUser && hasSystem) {
                    yield DSL.noCondition();
                } else if (hasUser) {
                    yield field("namespace").ne(systemNamespace);
                } else if (hasSystem) {
                    yield field("namespace").eq(systemNamespace);
                } else {
                    yield DSL.falseCondition();
                }
            }
            case NOT_IN -> {
                boolean hasUser = flowScopes.contains(FlowScope.USER);
                boolean hasSystem = flowScopes.contains(FlowScope.SYSTEM);
                if (hasUser && hasSystem) {
                    yield DSL.falseCondition();
                } else if (hasUser) {
                    yield field("namespace").eq(systemNamespace);
                } else if (hasSystem) {
                    yield field("namespace").ne(systemNamespace);
                } else {
                    yield DSL.noCondition();
                }
            }
            default -> throw new InvalidQueryFiltersException("Unsupported operation for SCOPE: " + operation);
        };
    }

